import type { Metadata } from "next"

import { ExpressBookingScreen } from "./ExpressBookingScreen"

export const metadata: Metadata = {
  title: "きっぷの予約 | さくら新幹線予約サービス",
  description: "特急・新幹線の空席照会と座席予約",
}

/**
 * 特急・新幹線 空席照会・予約 画面。
 *
 * page.tsx はサーバコンポーネント（関数 prop を一切持たない）。
 * 状態・関数 prop（formatValue / onValueChange / onToggle …）は
 * すべて ExpressBookingScreen の "use client" 境界内に閉じ込めている。
 */
export default function Page() {
  return <ExpressBookingScreen />
}

/**
 * 新幹線予約サービス — ドメインデータ（純粋・サーバ安全）。
 * 関数 prop は一切含めない（"use client" 境界の外でも import 可能）。
 */

export type SeatAvailability = "available" | "few" | "full"

/** 座席種別 */
export type SeatClass = "reserved" | "green" | "nonreserved"

export interface SeatClassMeta {
  id: SeatClass
  /** 普通車指定席 / グリーン車 / 普通車自由席 */
  label: string
  short: string
  /** 特急料金に上乗せされる席種ごとの料金（指定席料金 / グリーン料金）。自由席は 0。 */
  classFee: number
}

export const SEAT_CLASSES: SeatClassMeta[] = [
  { id: "reserved", label: "普通車指定席", short: "指定席", classFee: 5810 },
  { id: "green", label: "グリーン車", short: "グリーン", classFee: 11090 },
  { id: "nonreserved", label: "普通車自由席", short: "自由席", classFee: 4960 },
]

export interface TrainSeatStatus {
  reserved: SeatAvailability
  green: SeatAvailability
  nonreserved: SeatAvailability
}

export interface Train {
  id: string
  /** 列車名（のぞみ501号 など） */
  name: string
  /** 種別カテゴリ表示色のための系統（のぞみ/ひかり/こだま） */
  kind: "のぞみ" | "ひかり" | "こだま"
  /** 出発時刻 "HH:MM" */
  depart: string
  /** 到着時刻 "HH:MM" */
  arrive: string
  /** 所要（分） */
  durationMin: number
  seats: TrainSeatStatus
}

/** 東京 → 新大阪 の当日列車（抜粋） */
export const TRAINS: Train[] = [
  {
    id: "nozomi-501",
    name: "のぞみ501号",
    kind: "のぞみ",
    depart: "06:00",
    arrive: "08:27",
    durationMin: 147,
    seats: { reserved: "few", green: "available", nonreserved: "available" },
  },
  {
    id: "hikari-633",
    name: "ひかり633号",
    kind: "ひかり",
    depart: "06:33",
    arrive: "09:33",
    durationMin: 180,
    seats: { reserved: "available", green: "available", nonreserved: "available" },
  },
  {
    id: "nozomi-3",
    name: "のぞみ3号",
    kind: "のぞみ",
    depart: "06:50",
    arrive: "09:13",
    durationMin: 143,
    seats: { reserved: "available", green: "few", nonreserved: "few" },
  },
  {
    id: "kodama-695",
    name: "こだま695号",
    kind: "こだま",
    depart: "06:56",
    arrive: "10:54",
    durationMin: 238,
    seats: { reserved: "available", green: "available", nonreserved: "available" },
  },
  {
    id: "nozomi-205",
    name: "のぞみ205号",
    kind: "のぞみ",
    depart: "07:03",
    arrive: "09:30",
    durationMin: 147,
    seats: { reserved: "full", green: "few", nonreserved: "available" },
  },
  {
    id: "hikari-503",
    name: "ひかり503号",
    kind: "ひかり",
    depart: "07:26",
    arrive: "10:36",
    durationMin: 190,
    seats: { reserved: "few", green: "full", nonreserved: "available" },
  },
]

export const KIND_COLOR: Record<Train["kind"], string> = {
  のぞみ: "#0067c0",
  ひかり: "#e60012",
  こだま: "#00a040",
}

/** 区間の運賃（乗車券分）。席種に依らず一定。 */
export const BASE_FARE = 8910

/** 区間の特急料金の基準（通常期・指定席ベース）。種別ごとの差は classFee で表現する。 */
export const LIMITED_EXPRESS_BASE = 0

export function availabilityLabel(a: SeatAvailability): { symbol: string; text: string } {
  switch (a) {
    case "available":
      return { symbol: "○", text: "空席あり" }
    case "few":
      return { symbol: "△", text: "残りわずか" }
    case "full":
      return { symbol: "×", text: "満席" }
  }
}

export function formatDuration(min: number): string {
  const h = Math.floor(min / 60)
  const m = min % 60
  return h > 0 ? `${h}時間${m}分` : `${m}分`
}

/**
 * 座席表（号車内の 2+3 配列）。窓側 A/E、通路側 C/D、中央 B。
 * 一部を予約済 / 確保中にしておく。
 */
export interface SeatDef {
  id: string
  row: number
  col: string
  state?: "available" | "occupied" | "held"
  position?: "window" | "aisle" | "middle"
}

const COLS: { col: string; position: "window" | "aisle" | "middle" }[] = [
  { col: "A", position: "window" },
  { col: "B", position: "middle" },
  { col: "C", position: "aisle" },
  { col: "D", position: "aisle" },
  { col: "E", position: "window" },
]

const OCCUPIED = new Set(["8C", "9A", "9B", "10D", "11E", "12A", "12B", "13C"])
const HELD = new Set(["10A", "13D"])

export function buildSeats(): SeatDef[] {
  const seats: SeatDef[] = []
  for (let row = 8; row <= 14; row++) {
    for (const c of COLS) {
      const id = `${row}${c.col}`
      const state = OCCUPIED.has(id) ? "occupied" : HELD.has(id) ? "held" : "available"
      seats.push({ id, row, col: c.col, position: c.position, state })
    }
  }
  return seats
}

export const SEAT_COLUMNS: (string | null)[] = ["A", "B", "C", null, "D", "E"]

"use client"

import * as React from "react"
import {
  IconCalendarEvent,
  IconUser,
  IconInfoCircle,
} from "@tabler/icons-react"

import {
  PageHeader,
  BottomActionBar,
  Button,
  Badge,
  ListCard,
  LineChip,
  SegmentedControl,
  NumberInput,
  DatePicker,
  SeatMap,
  AmountBreakdown,
  Card,
  Separator,
  Stepper,
  type AmountLine,
  type StepperStep,
} from "@gunjo/ui"
import { ja } from "date-fns/locale"

import { RouteHeader, DepArr } from "./RouteHeader"
import {
  TRAINS,
  SEAT_CLASSES,
  KIND_COLOR,
  BASE_FARE,
  availabilityLabel,
  formatDuration,
  buildSeats,
  SEAT_COLUMNS,
  type SeatClass,
  type SeatAvailability,
  type Train,
} from "./data"

const yen = (n: number) => `¥${n.toLocaleString("ja-JP")}`

function AvailabilityCell({
  classShort,
  a,
}: {
  classShort: string
  a: SeatAvailability
}) {
  const { symbol, text } = availabilityLabel(a)
  const tone =
    a === "available"
      ? "text-success-strong"
      : a === "few"
        ? "text-warning"
        : "text-muted-foreground"
  return (
    <span className="inline-flex items-baseline gap-1 whitespace-nowrap text-xs">
      <span className="text-muted-foreground">{classShort}</span>
      <span className={tone} aria-hidden="true">
        {symbol}
      </span>
      <span className="sr-only">
        {classShort} {text}
      </span>
    </span>
  )
}

export function ExpressBookingScreen() {
  const [origin, setOrigin] = React.useState("東京")
  const [destination, setDestination] = React.useState("新大阪")
  const [date, setDate] = React.useState<Date | undefined>(new Date(2026, 6, 4))
  const [tripType, setTripType] = React.useState("oneway")
  const [adults, setAdults] = React.useState(1)
  const [children, setChildren] = React.useState(0)

  const [selectedTrainId, setSelectedTrainId] = React.useState<string>(TRAINS[0].id)
  const [seatClass, setSeatClass] = React.useState<SeatClass>("reserved")
  const [selectedSeats, setSelectedSeats] = React.useState<string[]>([])

  const seats = React.useMemo(() => buildSeats(), [])
  const selectedTrain = React.useMemo<Train>(
    () => TRAINS.find((t) => t.id === selectedTrainId) ?? TRAINS[0],
    [selectedTrainId]
  )

  const pax = adults + children
  const classMeta = SEAT_CLASSES.find((c) => c.id === seatClass)!
  const isReservedSeatClass = seatClass !== "nonreserved"

  // 自由席は座席指定なし → 種別を変えたら選択をクリア
  React.useEffect(() => {
    if (!isReservedSeatClass) setSelectedSeats([])
  }, [isReservedSeatClass])

  const handleSwap = () => {
    setOrigin(destination)
    setDestination(origin)
  }

  const handleSelectTrain = (id: string) => {
    setSelectedTrainId(id)
    setSelectedSeats([])
  }

  const toggleSeat = (seatId: string) => {
    setSelectedSeats((prev) =>
      prev.includes(seatId) ? prev.filter((s) => s !== seatId) : [...prev, seatId]
    )
  }

  // 料金計算（人数分）
  const fareTotal = BASE_FARE * pax
  const classFeeTotal = classMeta.classFee * pax
  const grandTotal = fareTotal + classFeeTotal

  const amountLines: AmountLine[] = [
    { type: "heading", label: "ご乗車券" },
    {
      label: `運賃（${origin} → ${destination}）`,
      amount: fareTotal,
      note: `${yen(BASE_FARE)} × ${pax}名`,
    },
    { type: "heading", label: "特急券" },
    {
      label:
        seatClass === "green"
          ? "特急料金＋グリーン料金"
          : seatClass === "nonreserved"
            ? "特急料金（自由席）"
            : "特急料金＋指定席料金",
      amount: classFeeTotal,
      note: `${classMeta.label} ${yen(classMeta.classFee)} × ${pax}名`,
    },
  ]

  const steps: StepperStep[] = [
    { label: "条件", state: "completed" },
    { label: "列車", state: "completed" },
    { label: "座席", state: isReservedSeatClass ? "current" : "completed" },
    { label: "確認", state: "upcoming" },
  ]

  const seatsNeeded = isReservedSeatClass ? pax : 0
  const seatsChosen = selectedSeats.length
  const canBook = !isReservedSeatClass || seatsChosen === seatsNeeded
  const seatHint = isReservedSeatClass
    ? `座席 ${seatsChosen} / ${seatsNeeded} 選択`
    : "自由席（座席指定なし）"

  const dateLabel = date
    ? `${date.getMonth() + 1}月${date.getDate()}日（${["日", "月", "火", "水", "木", "金", "土"][date.getDay()]}）`
    : "未選択"

  return (
    <div className="mx-auto flex min-h-full w-full max-w-md flex-col bg-background">
      <PageHeader
        title="きっぷの予約"
        subtitle="さくら新幹線予約サービス"
        onBack={() => undefined}
        actions={
          <Button variant="ghost" size="icon" aria-label="ご利用案内">
            <IconInfoCircle className="size-5" aria-hidden="true" />
          </Button>
        }
      />

      <div className="flex flex-1 flex-col gap-4 px-4 py-4">
        <Stepper steps={steps} aria-label="予約の進捗" />

        {/* 検索条件 */}
        <Card className="gap-3 p-4">
          <h2 className="text-sm font-semibold text-foreground">ご乗車区間・条件</h2>
          <RouteHeader
            origin={origin}
            destination={destination}
            onSwap={handleSwap}
          />
          <Separator />

          <div className="flex flex-col gap-3">
            <div className="flex flex-col gap-1.5">
              <label
                htmlFor="ride-date"
                className="inline-flex items-center gap-1.5 text-xs font-medium text-muted-foreground"
              >
                <IconCalendarEvent className="size-4" aria-hidden="true" />
                ご乗車日
              </label>
              <DatePicker
                id="ride-date"
                value={date}
                onValueChange={setDate}
                locale={ja}
                editable={false}
                calendarLabel="乗車日を選ぶ"
              />
            </div>

            <div className="flex flex-col gap-1.5">
              <span className="text-xs font-medium text-muted-foreground">片道 / 往復</span>
              <SegmentedControl
                aria-label="片道か往復か"
                value={tripType}
                onValueChange={setTripType}
                options={[
                  { value: "oneway", label: "片道" },
                  { value: "roundtrip", label: "往復" },
                ]}
              />
            </div>

            <fieldset className="flex flex-col gap-2">
              <legend className="inline-flex items-center gap-1.5 text-xs font-medium text-muted-foreground">
                <IconUser className="size-4" aria-hidden="true" />
                人数
              </legend>
              <div className="flex items-center justify-between gap-2">
                <span className="text-sm text-foreground">大人</span>
                <NumberInput
                  layout="stepper"
                  value={adults}
                  onValueChange={setAdults}
                  min={1}
                  max={6}
                  aria-label="大人の人数"
                  incrementLabel="大人を増やす"
                  decrementLabel="大人を減らす"
                />
              </div>
              <div className="flex items-center justify-between gap-2">
                <span className="text-sm text-foreground">小児</span>
                <NumberInput
                  layout="stepper"
                  value={children}
                  onValueChange={setChildren}
                  min={0}
                  max={6}
                  aria-label="小児の人数"
                  incrementLabel="小児を増やす"
                  decrementLabel="小児を減らす"
                />
              </div>
            </fieldset>
          </div>
        </Card>

        {/* 列車の一覧 */}
        <section className="flex flex-col gap-2" aria-label="列車の一覧">
          <div className="flex items-baseline justify-between">
            <h2 className="text-sm font-semibold text-foreground">列車を選ぶ</h2>
            <span className="text-xs text-muted-foreground">
              {dateLabel}・{TRAINS.length}本
            </span>
          </div>

          <ul className="flex flex-col gap-2">
            {TRAINS.map((train) => {
              const selected = train.id === selectedTrainId
              return (
                <li key={train.id}>
                  <ListCard
                    selected={selected}
                    onSelect={() => handleSelectTrain(train.id)}
                    leading={
                      <LineChip label={train.kind} color={KIND_COLOR[train.kind]} />
                    }
                    title={
                      <span className="flex flex-col gap-0.5">
                        <span className="text-xs font-normal text-muted-foreground">
                          {train.name}
                        </span>
                        <DepArr depart={train.depart} arrive={train.arrive} />
                      </span>
                    }
                    description={`所要 ${formatDuration(train.durationMin)}`}
                    tags={
                      <>
                        <AvailabilityCell classShort="指定" a={train.seats.reserved} />
                        <AvailabilityCell classShort="グリーン" a={train.seats.green} />
                        <AvailabilityCell classShort="自由" a={train.seats.nonreserved} />
                      </>
                    }
                    status={
                      selected ? (
                        <Badge variant="info">選択中</Badge>
                      ) : undefined
                    }
                  />
                </li>
              )
            })}
          </ul>
        </section>

        {/* 座席種別・人数（種別トグル） */}
        <section className="flex flex-col gap-2" aria-label="座席種別">
          <h2 className="text-sm font-semibold text-foreground">座席種別</h2>
          <SegmentedControl
            aria-label="座席種別を選ぶ"
            value={seatClass}
            onValueChange={(v) => setSeatClass(v as SeatClass)}
            options={SEAT_CLASSES.map((c) => ({ value: c.id, label: c.short }))}
          />
          <p className="text-xs text-muted-foreground">
            {classMeta.label}・{yen(classMeta.classFee)}/名（特急料金込み）
          </p>
        </section>

        {/* 座席の選択 */}
        <section className="flex flex-col gap-2" aria-label="座席の選択">
          <div className="flex items-baseline justify-between">
            <h2 className="text-sm font-semibold text-foreground">座席を選ぶ</h2>
            <span className="text-xs text-muted-foreground">
              {selectedTrain.name}・8号車
            </span>
          </div>

          {isReservedSeatClass ? (
            <Card className="gap-2 p-4">
              <p className="text-xs text-muted-foreground">
                {pax}名分（窓側 A・E / 通路側 C・D）を選んでください
              </p>
              <SeatMap
                columns={SEAT_COLUMNS}
                seats={seats}
                selectedIds={selectedSeats}
                onToggle={toggleSeat}
                maxSelectable={pax}
                label={`${selectedTrain.name} 8号車 座席表`}
              />
            </Card>
          ) : (
            <Card className="items-start gap-1 p-4">
              <Badge variant="secondary">座席指定なし</Badge>
              <p className="text-xs text-muted-foreground">
                自由席は座席のご指定はできません。ご乗車日当日、自由席車両を
                ご利用ください。
              </p>
            </Card>
          )}
        </section>

        {/* 運賃・料金 */}
        <section className="flex flex-col gap-2" aria-label="運賃・料金">
          <h2 className="text-sm font-semibold text-foreground">運賃・料金</h2>
          <Card className="p-4">
            <AmountBreakdown
              lines={amountLines}
              total={{ label: "合計", amount: grandTotal }}
              formula={`合計 = 運賃 ＋ 特急料金（${classMeta.label}）／ ${pax}名`}
              formatValue={yen}
            />
          </Card>
        </section>
      </div>

      <BottomActionBar
        actions={
          <Button size="lg" disabled={!canBook}>
            きっぷを予約する
          </Button>
        }
      >
        <div className="flex flex-col">
          <span className="text-lg font-bold tabular-nums text-foreground">
            {yen(grandTotal)}
          </span>
          <span className="text-xs text-muted-foreground">{seatHint}</span>
        </div>
      </BottomActionBar>
    </div>
  )
}

"use client"

import * as React from "react"
import { IconArrowsExchange, IconArrowRight } from "@tabler/icons-react"

import { cn } from "@gunjo/ui"

/**
 * RouteHeader — ご乗車区間（出発駅 → 到着駅）の A→B ヘッダー。
 *
 * NOTE(adopter): @gunjo/ui に origin→destination の A→B プリミティブが無いため、
 * ここはページ固有グルーとして手書きしている。`RouteStops` / `Itinerary` は
 * 縦の順序付きタイムライン、`LineChip` は路線識別チップで、いずれも
 * 「出発駅 大きく → 到着駅 大きく ＋ 入れ替え」という横並びの照会ヘッダーには合わない。
 */
export interface RouteHeaderProps {
  origin: string
  destination: string
  /** 出発⇄到着の入れ替え。 */
  onSwap?: () => void
  /** 駅名をタップで編集する場合のハンドラ。 */
  onEditOrigin?: () => void
  onEditDestination?: () => void
  className?: string
}

function Station({
  caption,
  name,
  onEdit,
  align,
}: {
  caption: string
  name: string
  onEdit?: () => void
  align: "start" | "end"
}) {
  const body = (
    <span className={cn("flex min-w-0 flex-col", align === "end" ? "items-end text-right" : "items-start text-left")}>
      <span className="text-[11px] font-medium text-muted-foreground">{caption}</span>
      <span className="truncate text-xl font-bold leading-tight text-foreground">{name}</span>
    </span>
  )
  if (!onEdit) return <span className="min-w-0 flex-1">{body}</span>
  return (
    <button
      type="button"
      onClick={onEdit}
      className={cn(
        "min-w-0 flex-1 rounded-md px-1 py-0.5 outline-none transition-colors hover:bg-muted focus-visible:ring-2 focus-visible:ring-ring",
        align === "end" ? "text-right" : "text-left"
      )}
      aria-label={`${caption}（${name}）を変更`}
    >
      {body}
    </button>
  )
}

export function RouteHeader({
  origin,
  destination,
  onSwap,
  onEditOrigin,
  onEditDestination,
  className,
}: RouteHeaderProps) {
  return (
    <div
      className={cn("flex items-center gap-1", className)}
      role="group"
      aria-label={`ご乗車区間 ${origin} から ${destination}`}
    >
      <Station caption="出発駅" name={origin} onEdit={onEditOrigin} align="start" />

      {onSwap ? (
        <button
          type="button"
          onClick={onSwap}
          aria-label="出発駅と到着駅を入れ替える"
          className="inline-flex size-9 shrink-0 items-center justify-center rounded-full border border-border bg-background text-muted-foreground outline-none transition-colors hover:bg-muted hover:text-foreground focus-visible:ring-2 focus-visible:ring-ring"
        >
          <IconArrowsExchange className="size-5" aria-hidden="true" />
        </button>
      ) : (
        <IconArrowRight className="size-5 shrink-0 text-muted-foreground" aria-hidden="true" />
      )}

      <Station caption="到着駅" name={destination} onEdit={onEditDestination} align="end" />
    </div>
  )
}

/**
 * DepArr — 1列車の 発 → 着（コンパクトな A→B）。同じく専用プリミティブが無いため手書き。
 */
export function DepArr({
  depart,
  arrive,
  className,
}: {
  depart: string
  arrive: string
  className?: string
}) {
  return (
    <span
      className={cn("inline-flex items-baseline gap-1.5 tabular-nums", className)}
      aria-label={`${depart} 発 ${arrive} 着`}
    >
      <span className="text-lg font-bold leading-none text-foreground">{depart}</span>
      <span className="text-[10px] font-medium text-muted-foreground">発</span>
      <IconArrowRight className="size-3.5 shrink-0 self-center text-muted-foreground" aria-hidden="true" />
      <span className="text-lg font-bold leading-none text-foreground">{arrive}</span>
      <span className="text-[10px] font-medium text-muted-foreground">着</span>
    </span>
  )
}
